INSERT INTO entries (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES 
('c++', 41, 'beginner', 1, '数组声明与初始化', '["数组","声明","初始化"]', '介绍C++中数组的声明和基本初始化方法。', '数组是C++中用于存储多个相同类型元素的数据结构。声明数组需要指定元素类型和数组大小。例如，`int arr[5];` 声明一个可以存储5个整数的数组。数组可以在声明时初始化，如 `int arr[5] = {1,2,3,4,5};`。如果初始化列表中的元素少于数组大小，剩余元素将被初始化为0。如果不指定大小，编译器会根据初始化列表推断大小，如 `int arr[] = {1,2,3};` 将创建一个大小为3的数组。', '["int arr[5];", "int arr[5] = {1,2,3,4,5};", "int arr[] = {1,2,3};"]', '["声明了一个大小为5的整数数组", "数组初始化为值{1,2,3,4,5}", "数组大小自动推断为3，初始化为{1,2,3}"]'),
('c++', 42, 'beginner', 1, '访问数组元素', '["数组","访问","索引"]', '学习如何使用索引访问和修改数组元素。', '在C++中，数组元素通过从0开始的索引访问。例如，对于数组 `int arr[5] = {10,20,30,40,50};`，`arr[0]` 访问第一个元素，值为10。索引必须在数组范围内，否则会导致未定义行为。可以使用索引来读取或修改元素值。', '["int arr[5] = {10,20,30,40,50};\\nstd::cout << arr[0];", "arr[2] = 100;"]', '["输出: 10", "修改后arr[2]的值为100"]'),
('c++', 43, 'beginner', 1, '数组遍历', '["数组","遍历","循环"]', '使用循环遍历数组中的所有元素。', '遍历数组通常使用for循环。可以通过数组大小来控制循环次数。例如，使用 `for(int i=0; i<5; i++)` 来遍历一个大小为5的数组。在循环体内访问 `arr[i]` 以处理每个元素。', '["int arr[5] = {1,2,3,4,5};\\nfor(int i=0; i<5; i++) {\\n  std::cout << arr[i] << \\" \\";\\n}"]', '["输出: 1 2 3 4 5"]'),
('c++', 44, 'beginner', 1, '数组大小与sizeof', '["数组","大小","sizeof"]', '使用sizeof运算符获取数组的大小。', '在C++中，可以使用sizeof运算符来获取数组的总字节数或元素个数。例如，对于数组 `int arr[5];`，`sizeof(arr)` 返回整个数组的字节数，`sizeof(arr)/sizeof(arr[0])` 返回元素个数。注意，这只适用于静态数组，不适用于指针或动态数组。', '["int arr[5] = {1,2,3,4,5};\\nstd::cout << sizeof(arr);", "int size = sizeof(arr)/sizeof(arr[0]);\\nstd::cout << size;"]', '["输出: 20 (假设int为4字节)", "输出: 5"]'),
('c++', 45, 'beginner', 1, '多维数组简介', '["数组","多维","二维"]', '介绍C++中的二维数组声明和访问。', '多维数组是数组的数组。例如，二维数组可以声明为 `int arr[3][4];`，表示3行4列的整数数组。访问元素使用两个索引，如 `arr[1][2]` 访问第二行第三列的元素。初始化可以在声明时进行，如 `int arr[2][3] = {{1,2,3},{4,5,6}};`。', '["int arr[3][4];", "int arr[2][3] = {{1,2,3},{4,5,6}};\\nstd::cout << arr[1][2];"]', '["声明了一个3x4的整数数组", "输出: 6"]');